/* selectWarehouseUserSelectBox */
select C.WAREKEY as COMBOVL , C.WHNAMLC as COMBONM from SUSRMA S inner join SROLGR A on S.COMPKEY = A.COMPKEY and S.ROLGKEY = A.ROLGKEY inner join SROLWH B on A.COMPKEY = B.COMPKEY and A.ROLEKEY = B.ROLEKEY inner join MWARMA C on B.COMPKEY = C.COMPKEY and B.WAREKEY = C.WAREKEY where S.COMPKEY = #{userData.compkey} and S.USERACT = #{userData.useract} and B.WAREAVL = 'Y'
and C.WHUSEYN = #{whuseyn}
and C.WHUSEYN = 'Y'
order by C.WAREKEY
SELECT IFNULL(R.USE_YN,'N') AS USE_YN , W.WAREKEY as COMBOVL , W.WHNAMLC as COMBONM FROM MWARMA W LEFT JOIN V_SROLWH R ON W.WAREKEY = R.WAREKEY AND R.URGROUP_ID = #{userData.rgropid} WHERE W.COMPKEY = #{userData.compkey} AND IFNULL(R.USE_YN,'N') = 'Y' ORDER BY W.WAREKEY ASC

/* selectMaremaList */ select concat(MA.COMPKEY, MA.WAREKEY, MA.AREAKEY) as ROWKEY , MA.COMPKEY, MA.WAREKEY, MA.AREAKEY, MA.AREANAM , MA.ARUSEYN, MA.AREATYP, MA.SYONLYN , FN_COM_TODATE(MA.CREDATE) as CREDATE , FN_COM_TOTIME(MA.CRETIME) as CRETIME , fn_sy_usernam(MA.COMPKEY , MA.CREUSER) as CREUSER , FN_COM_TODATE(MA.LMODATE) as LMODATE , FN_COM_TOTIME(MA.LMOTIME) as LMOTIME , fn_sy_usernam(MA.COMPKEY , MA.LMOUSER) as LMOUSER , MA.UPDTCHK from MAREMA MA where MA.COMPKEY = #{userData.compkey}
and MA.WAREKEY = #{warekey}
and upper(MA.AREANAM) LIKE CONCAT('%', upper(#{areanam}), '%')
order by MA.COMPKEY, MA.WAREKEY, MA.AREAKEY

