/* selectMzonmaList */ select concat(MZ.COMPKEY, MZ.WAREKEY, MZ.AREAKEY, MZ.ZONEKEY) as ROWKEY , MZ.COMPKEY, MZ.WAREKEY, MZ.AREAKEY, MA.AREANAM as AREANAM , MZ.ZONEKEY, MZ.ZOUSEYN, MZ.ZONENAM, MZ.ZONETYP, MZ.ZOBUILD , MZ.ZOFLOOR, MZ.PUTAWYN, MZ.ALLOCYN, MZ.MOVEOYN, MZ.MOVEIYN , MZ.MIQTYYN, MZ.ZOTEMTY, MZ.SYONLYN , FN_COM_TODATE(MZ.CREDATE) as CREDATE, FN_COM_TOTIME(MZ.CRETIME) as CRETIME, fn_sy_usernam(MZ.COMPKEY, MZ.CREUSER) as CREUSER , FN_COM_TODATE(MZ.LMODATE) as LMODATE, FN_COM_TOTIME(MZ.LMOTIME) as LMOTIME, fn_sy_usernam(MZ.COMPKEY, MZ.LMOUSER) as LMOUSER , MZ.UPDTCHK from MZONMA MZ inner join MWARMA MW on MW.COMPKEY = MZ.COMPKEY and MW.WAREKEY = MZ.WAREKEY inner join MAREMA MA on MA.COMPKEY = MZ.COMPKEY and MA.WAREKEY = MZ.WAREKEY and MA.AREAKEY = MZ.AREAKEY where MZ.COMPKEY = #{userData.compkey}
and MZ.WAREKEY = #{warekey}
and upper(MA.AREANAM) like CONCAT('%', upper(#{areanam}), '%')
and upper(MZ.ZONENAM) like CONCAT('%', upper(#{zonenam}), '%')
order by MZ.COMPKEY, MZ.WAREKEY, MZ.AREAKEY, MZ.ZONEKEY

