/* selectWareAreaRelations */ select MWA.WAREKEY as WAREKEY, MAR.AREAKEY as AREAKEY , MAR.AREANAM as AREANAM from MWARMA MWA inner join MAREMA MAR on (MWA.COMPKEY = MAR.COMPKEY and MWA.WAREKEY = MAR.WAREKEY) where MWA.COMPKEY = #{userData.compkey} and MWA.WHUSEYN = 'Y' and MAR.ARUSEYN = 'Y'
and MWA.WAREKEY = #{warekey}
and MAR.AREANAM like '%',#{areanam},'%')
group by MWA.WAREKEY, MAR.AREAKEY, MAR.AREANAM order by MWA.WAREKEY, MAR.AREAKEY

/* selectMlocmaList */ select concat(ML.COMPKEY, ML.WAREKEY, ML.AREAKEY, ML.ZONEKEY, ML.LOCAKEY) as ROWKEY , ML.COMPKEY, ML.WAREKEY, ML.WAREKEY as WHNAMLC, ML.AREAKEY , MA.AREANAM as AREANAM , ML.ZONEKEY, MZ.ZONENAM as ZONENAM, ML.LOCAKEY, ML.LOCANAM, ML.LOUSEYN , ML.LOCTYPE, ML.CAPACHK, ML.LOCSTAT, ML.LOCDEPT, ML.LOCWIDH , ML.LOCHEIG, ML.LOCCUBI, ML.LOCWEIG, ML.INBRTNO, ML.OTBRTNO , ML.MIXDSKU, ML.MIXDLOT, ML.REMTLOC, ML.USPTLOC, ML.USPKLOC , ML.BLOCKID, ML.PHYSROW, ML.PHYSSEC, ML.PHYSFLO, ML.EQUSTAT , FN_COM_TODATE(ML.CREDATE) as CREDATE , FN_COM_TOTIME(ML.CRETIME) as CRETIME , fn_sy_usernam(ML.COMPKEY , ML.CREUSER) as CREUSER , FN_COM_TODATE(ML.LMODATE) as LMODATE , FN_COM_TOTIME(ML.LMOTIME) as LMOTIME , fn_sy_usernam(ML.COMPKEY , ML.LMOUSER) as LMOUSER , ML.UPDTCHK from MLOCMA ML inner join MWARMA MW on ML.COMPKEY = MW.COMPKEY and ML.WAREKEY = MW.WAREKEY inner join MAREMA MA on ML.COMPKEY = MA.COMPKEY and ML.WAREKEY = MA.WAREKEY and ML.AREAKEY = MA.AREAKEY inner join MZONMA MZ on ML.COMPKEY = MZ.COMPKEY and ML.WAREKEY = MZ.WAREKEY and ML.AREAKEY = MZ.AREAKEY and ML.ZONEKEY = MZ.ZONEKEY where ML.COMPKEY = #{userData.compkey}
and ML.WAREKEY = #{warekey}
and upper(MW.WHNAMLC) like CONCAT('%', upper(#{whnamlc}), '%')
and ML.AREAKEY = #{areakey}
and upper(MA.AREANAM) like CONCAT('%', upper(#{areanam}), '%')
and ML.ZONEKEY = #{zonekey}
and upper(MZ.ZONENAM) like CONCAT('%', upper(#{zonenam}), '%')
and ML.LOCAKEY like CONCAT('%', upper(#{locakey}), '%')
and upper(ML.LOCANAM) like CONCAT('%', upper(#{locanam}), '%')
and ML.LOUSEYN = #{louseyn}
and ML.LOCTYPE = #{loctype}
and ML.LOCSTAT = #{locstat}
and ML.EQUSTAT = #{equstat}
order by ML.COMPKEY, ML.WAREKEY, ML.AREAKEY, ML.ZONEKEY, ML.LOCAKEY

