/* insertMlocma */
insert into MLOCMA
( COMPKEY , WAREKEY , AREAKEY , ZONEKEY , LOCAKEY
, LOUSEYN , LOCANAM , LOCTYPE , CAPACHK, LOCSTAT
, LOCDEPT , LOCWIDH , LOCHEIG , LOCCUBI , LOCWEIG
, INBRTNO , OTBRTNO , MIXDSKU, MIXDLOT , REMTLOC
, USPTLOC , USPKLOC , BLOCKID, PHYSROW , PHYSSEC
, PHYSFLO , EQUSTAT
, CREDATE , CRETIME , CREUSER , LMODATE , LMOTIME , LMOUSER )
values
( #{compkey}, #{warekey}, #{areakey}, #{zonekey}, #{locakey}
, #{louseyn}, #{locanam}, #{loctype}, #{capachk}, #{locstat}
, #{locdept}, #{locwidh} , #{locheig}, #{loccubi}, #{locweig}
, #{inbrtno}, #{otbrtno}, #{mixdsku}, #{mixdlot}, #{remtloc}
, #{usptloc}, #{uspkloc}, #{blockid}, #{physrow}, #{physsec}
, #{physflo}, #{equstat}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract}
, to_char(NOW() ,'YYYYMMDD'), to_char(NOW() ,'hh24miss'), #{userData.useract} )

