/* selectMlocmaSelectBox */
select LOCAKEY as COMBOVL
, LOCANAM as COMBONM
from MLOCMA
where COMPKEY = #{userData.compkey}

	and WAREKEY = #{warekey}


	and AREAKEY = #{areakey}


	and ZONEKEY = #{zonekey}


	and LOCAKEY = #{locakey}



		and LOUSEYN = #{louseyn}


		and LOUSEYN = 'Y'



	and LOCTYPE = #{loctype}


	and LOCSTAT = #{locstat}

group by LOCAKEY, LOCANAM
order by LOCAKEY, LOCANAM

/* selectMlocma */ select ML.COMPKEY, ML.WAREKEY, ML.AREAKEY, ML.ZONEKEY , ML.LOCAKEY, ML.LOCANAM, ML.LOUSEYN, ML.LOCTYPE , ML.CAPACHK, ML.LOCSTAT, ML.LOCDEPT, ML.LOCWIDH , ML.LOCHEIG, ML.LOCCUBI, ML.LOCWEIG, ML.INBRTNO , ML.OTBRTNO, ML.MIXDSKU, ML.MIXDLOT, ML.REMTLOC , ML.USPTLOC, ML.USPKLOC, ML.BLOCKID, ML.PHYSROW , ML.PHYSSEC, ML.PHYSFLO, ML.EQUSTAT , FN_COM_TODATE(ML.CREDATE) as CREDATE , FN_COM_TOTIME(ML.CRETIME) as CRETIME , fn_sy_usernam(ML.COMPKEY , ML.CREUSER) as CREUSER , FN_COM_TODATE(ML.LMODATE) as LMODATE , FN_COM_TOTIME(ML.LMOTIME) as LMOTIME , fn_sy_usernam(ML.COMPKEY , ML.LMOUSER) as LMOUSER , ML.UPDTCHK from MLOCMA ML inner join MWARMA MW on ML.COMPKEY = MW.COMPKEY and ML.WAREKEY = MW.WAREKEY inner join MAREMA MA on ML.COMPKEY = MA.COMPKEY and ML.WAREKEY = MA.WAREKEY and ML.AREAKEY = MA.AREAKEY inner join MZONMA MZ on ML.COMPKEY = MZ.COMPKEY and ML.WAREKEY = MZ.WAREKEY and ML.AREAKEY = MZ.AREAKEY and ML.ZONEKEY = MZ.ZONEKEY where ML.COMPKEY = #{userData.compkey}
and ML.WAREKEY = #{warekey}
and ML.AREAKEY = #{areakey}
and ML.ZONEKEY = #{zonekey}
and ML.LOCAKEY = #{locakey}
and ML.LOUSEYN = #{louseyn}
and ML.LOUSEYN = 'Y'
and ML.LOCTYPE = #{loctype}
and ML.LOCSTAT = #{locstat}
and ML.EQUSTAT = #{equstat}

/* selectWareAreaZoneRelations */
select MWA.WAREKEY as WAREKEY, MAR.AREAKEY as AREAKEY, MZO.ZONEKEY as ZONEKEY
, MAR.AREANAM as AREANAM, MZO.ZONENAM as ZONENAM
from MWARMA MWA
inner join MAREMA MAR on (MWA.COMPKEY = MAR.COMPKEY and MWA.WAREKEY = MAR.WAREKEY)
inner join MZONMA MZO on (MAR.COMPKEY = MZO.COMPKEY and MWA.WAREKEY = MZO.WAREKEY and MAR.AREAKEY = MZO.AREAKEY)
where MWA.COMPKEY = #{userData.compkey}
and MWA.WHUSEYN = 'Y' and MAR.ARUSEYN = 'Y' and MZO.ZOUSEYN = 'Y'

	and MWA.WAREKEY = #{warekey}


	and MAR.AREAKEY = #{areakey}


	and MZO.ZONEKEY = #{zonekey}

group by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY, MAR.AREANAM, MZO.ZONENAM
order by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY

/* selectWareAreaZoneLocationRelations */
select MWA.WAREKEY as WAREKEY, MAR.AREAKEY as AREAKEY, MZO.ZONEKEY as ZONEKEY
,MAR.AREANAM as AREANAM, MZO.ZONENAM as ZONENAM, MLO.LOCAKEY as LOCAKEY, MLO.LOCANAM as LOCANAM
from MWARMA MWA
inner join MAREMA MAR on (MWA.COMPKEY = MAR.COMPKEY and MWA.WAREKEY = MAR.WAREKEY)
inner join MZONMA MZO on (MAR.COMPKEY = MZO.COMPKEY and MWA.WAREKEY = MZO.WAREKEY and MAR.AREAKEY = MZO.AREAKEY)
inner join MLOCMA MLO on (MZO.COMPKEY = MLO.COMPKEY and MWA.WAREKEY = MLO.WAREKEY and MAR.AREAKEY = MLO.AREAKEY and MLO.ZONEKEY = MZO.ZONEKEY)
where MWA.COMPKEY = #{userData.compkey}
and MWA.WHUSEYN = 'Y' and MAR.ARUSEYN = 'Y' and MZO.ZOUSEYN = 'Y' and MLO.LOUSEYN = 'Y'

	and MWA.WAREKEY = #{warekey}


	and MAR.AREAKEY = #{areakey}


	and MZO.ZONEKEY = #{zonekey}

group by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY, MLO.LOCAKEY, MAR.AREANAM, MZO.ZONENAM, MLO.LOCANAM
order by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY, MLO.LOCAKEY

/* selectWareAreaZoneLocationRelationsWmt10 */
select MWA.WAREKEY as WAREKEY, MAR.AREAKEY as AREAKEY, MZO.ZONEKEY as ZONEKEY
, MAR.AREANAM as AREANAM, MZO.ZONENAM as ZONENAM, MLO.LOCAKEY as LOCAKEY, MLO.LOCANAM as LOCANAM,
MLO.LOCAKEY as TOLOCKY 
from MWARMA MWA
inner join MAREMA MAR on (MWA.COMPKEY = MAR.COMPKEY and MWA.WAREKEY = MAR.WAREKEY)
inner join MZONMA MZO on (MAR.COMPKEY = MZO.COMPKEY and MWA.WAREKEY = MZO.WAREKEY and MAR.AREAKEY = MZO.AREAKEY)
inner join MLOCMA MLO on (MZO.COMPKEY = MLO.COMPKEY and MWA.WAREKEY = MLO.WAREKEY and MAR.AREAKEY = MLO.AREAKEY and MLO.ZONEKEY = MZO.ZONEKEY)
where MWA.COMPKEY = #{userData.compkey}
and MWA.WHUSEYN = 'Y' and MAR.ARUSEYN = 'Y' and MZO.ZOUSEYN = 'Y' and MLO.LOUSEYN = 'Y'

	and MWA.WAREKEY = #{warekey}


	and MAR.AREAKEY = #{areakey}


	and MZO.ZONEKEY = #{zonekey}

group by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY, MLO.LOCAKEY, MAR.AREANAM, MZO.ZONENAM, MLO.LOCANAM
order by MWA.WAREKEY, MAR.AREAKEY, MZO.ZONEKEY, MLO.LOCAKEY
